      "term": "Pythagoras’ Theorem",
      "simpleDefinition": "A formula used to calculate the length of a missing side in a right-angled triangle.",
      "anchor": "Calculating the total impedance (hypotenuse) from resistance and reactance.",
      "misconception": "Forgetting to square the individual sides or forgetting to square-root the final sum."
    },
    {
      "term": "Trigonometry",
      "simpleDefinition": "The branch of maths dealing with the relationship between the sides and angles of triangles.",
      "anchor": "Using SOHCAHTOA to find the phase angle in an AC circuit.",
      "misconception": "Confusing which sides are the 'Opposite' and 'Adjacent' relative to the angle being calculated."
    },
    {
      "term": "Algebra",
      "simpleDefinition": "A system where letters are used to represent unknown numbers in a formula.",
      "anchor": "Using V, I, and R to represent Voltage, Current, and Resistance in Ohm's Law.",
      "misconception": "Believing that letters in a formula are just labels rather than placeholders for numerical values."
    },
    {
      "term": "Mean (Statistics)",
      "simpleDefinition": "The average value calculated by adding all numbers in a set and dividing by the total count.",
      "anchor": "Averaging three separate continuity test results to get a final reading.",
      "misconception": "Assuming 'average' always means the middle number in a list without doing the calculation."
    }
  ],
  "anchorPhrases": [
    "Change the side, change the operation.",
    "SOHCAHTOA: Sine, Cosine, Tangent.",
    "Powers of 10 for metric units.",
    "Isolate the unknown value."
  ],
  "misconceptionTargets": [
    "Indices are not simple multiplication.",
    "Transposition requires reversing the operation.",
    "The hypotenuse is always the longest side of the triangle.",
